  ('locality-d0d1b9a2-moex-00107', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X3年期初應收帳款備抵損失有貸方餘額$60,300，X3年6月15日該公司沖銷應收帳 款$28,650，收回原先已沖銷的應收帳款$10,050，X3年12月31日提列的預期信用減損損失 為$42,716，X3年12月31日公司合理估計應收帳款餘額的8%可能無法收回，試問甲公司 X3年12月31日應收帳款的餘額為何？', '["$521,250", "$533,950", "$1,055,200", "$1,413,325"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00108', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司銷貨收到一張面額$150,000，6個月到期，利率6%之票據。在收到票據2個月後即持 向某銀行貼現，貼現息為10%，試問甲公司將自銀行收到多少現金？', '["$154,500", "$150,000", "$149,350", "$140,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00109', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲牧場X2年1月1日以$240,000購入4隻綿羊以生產羊毛。X2年間飼養綿羊之成本包含 飼料$60,000，專屬飼養人員薪資$200,000。若綿羊X2年12月31日之公允價值為$260,000， 出售成本為$8,000，則甲牧場X2年底資產負債表中綿羊之列示金額為何？', '["$252,000", "$260,000", "$300,000", "$500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00110', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', 'X2年1月初甲公司依股權淨值取得乙公司25%普通股股權。甲公司依權益法處理此投資， X2年初該投資帳戶餘額為$320,000，X2年底該投資帳戶餘額為$400,000。假設乙公司X2年 度宣告並發放現金股利$50,000，則乙公司X2年度之淨利為何？', '["$80,000", "$130,000", "$320,000", "$370,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00111', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X2年1月1日發行5年期公司債，面額$100,000，票面利率10%，每年12月31日 付息，在支付發行公司債之交易成本後，甲公司發行時的淨現金流入為$107,685（原始有效 利率為 8%），公司採有效利息法攤銷折溢價，X4 年 1 月 1 日該公司決定在公開市場以 $106,250買回公司債，買回時有關金融負債除列之損益為何？', '["損失$1,446", "損失$1,639", "利益$3,125", "利益$1,563"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00112', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司X3年3月1日首次以$120,000買進6,000股庫藏股，5月賣出2,000股庫藏股，售得 $50,000，7 月再將剩下的庫藏股全數售出，售得$64,000。試問 7 月之庫藏股交易對甲公司 X3年財務報表之影響為何？', '["增加出售庫藏股損失$16,000", "增加出售庫藏股損失$10,000", "減少保留盈餘$6,000", "增加資本公積－庫藏股票交易$10,000 50420"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00113', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-113-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', 'X1年7月1日甲公司可轉換公司債持有人行使$200,000可轉換公司債的轉換權（轉換價格 為$50），轉換日公司的股價為$56，股票面額$10，應付公司債折價為$6,400，資本公積-認 股權為$10,000。則轉換時之分錄應包括：', '["貸：資本公積－普通股股票溢價$163,600", "貸：資本公積－普通股股票溢價$160,000", "借：資本公積－認股權$30,400", "借：公司債轉換損失$30,400"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:06+00:00", "source_pdf_sha1": "0ca29266df5e", "answer_pdf_sha1": "0b94159ca517", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
